import{_ as a,o as e,c as d,a2 as n}from"./chunks/framework.BFVZdVmd.js";const u=JSON.parse('{"title":"核心框架","description":"","frontmatter":{},"headers":[],"relativePath":"framework/index.md","filePath":"framework/index.md","lastUpdated":null}'),r={name:"framework/index.md"};function o(i,t,s,l,p,h){return e(),d("div",null,[...t[0]||(t[0]=[n(`<h1 id="核心框架" tabindex="-1">核心框架 <a class="header-anchor" href="#核心框架" aria-label="Permalink to &quot;核心框架&quot;">​</a></h1><p>核心框架层是整个微服务体系的骨架，负责服务的启动、治理、注册发现、流量入口、远程调用和稳定性保障。</p><h2 id="组件清单" tabindex="-1">组件清单 <a class="header-anchor" href="#组件清单" aria-label="Permalink to &quot;组件清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>作用</th><th>说明</th></tr></thead><tbody><tr><td><a href="./spring-boot">Spring Boot</a></td><td>基础开发框架</td><td>单个微服务的基础，负责应用启动、自动配置和接口开发，基本必用。</td></tr><tr><td><a href="./spring-cloud">Spring Cloud</a></td><td>微服务治理</td><td>服务注册、远程调用、网关、熔断限流等微服务能力。</td></tr><tr><td><a href="./nacos">Nacos</a></td><td>注册配置中心</td><td>服务注册与发现 + 统一配置管理，国内项目推荐。</td></tr><tr><td><a href="./gateway">Spring Cloud Gateway</a></td><td>网关</td><td>微服务统一入口，负责路由、鉴权、限流、跨域、灰度。</td></tr><tr><td><a href="./openfeign">OpenFeign</a></td><td>服务调用</td><td>声明式 HTTP 客户端，以接口方式完成服务间远程调用。</td></tr><tr><td><a href="./sentinel">Sentinel</a></td><td>熔断限流</td><td>限流、熔断、降级、热点参数限流，国内项目常用。</td></tr></tbody></table><h2 id="层次关系" tabindex="-1">层次关系 <a class="header-anchor" href="#层次关系" aria-label="Permalink to &quot;层次关系&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Spring Boot          每个微服务本质上都是一个 Spring Boot 应用</span></span>
<span class="line"><span>  + Spring Cloud     在 Boot 之上提供微服务治理能力</span></span>
<span class="line"><span>  + Spring Cloud Alibaba   国内常用扩展，整合 Nacos / Sentinel / RocketMQ / Seata</span></span></code></pre></div><p>Spring Boot 是基础，Spring Cloud 提供治理能力，Spring Cloud Alibaba 是国内项目常用的一套微服务组件集成。</p>`,7)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
